"use client";

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";
import { useAudioDevices, type AudioDevice } from "@/hooks/use-audio-devices";

// =============================================================================
// TYPES
// =============================================================================

interface MicSelectorProps
  extends
    Omit<React.ComponentProps<"div">, "onSelect">,
    VariantProps<typeof micSelectorVariants> {
  /** Called when a device is selected */
  onDeviceSelect?: (device: AudioDevice) => void;
  /** Called when active stream changes */
  onStreamChange?: (stream: MediaStream | null) => void;
  /** Whether to show a preview level indicator */
  showPreview?: boolean;
  /** Device kind filter. Default: "audioinput" */
  kind?: MediaDeviceKind;
}

// =============================================================================
// VARIANTS
// =============================================================================

const micSelectorVariants = cva(
  "flex flex-col gap-2 rounded-xl border border-border bg-background p-3",
  {
    variants: {
      size: {
        sm: "p-2 gap-1.5 text-sm",
        md: "p-3 gap-2 text-sm",
        lg: "p-4 gap-3 text-base",
      },
    },
    defaultVariants: {
      size: "md",
    },
  }
);

// =============================================================================
// LEVEL PREVIEW HOOK
// =============================================================================

function useLevelPreview(stream: MediaStream | null, enabled: boolean) {
  const [level, setLevel] = React.useState(0);
  const rafRef = React.useRef<number | null>(null);
  const analyserRef = React.useRef<AnalyserNode | null>(null);

  React.useEffect(() => {
    if (!enabled || !stream) {
      setLevel(0);
      return;
    }

    let cancelled = false;
    try {
      const AudioContextClass =
        window.AudioContext ||
        (window as unknown as { webkitAudioContext: typeof AudioContext })
          .webkitAudioContext;
      const audioCtx = new AudioContextClass();
      const source = audioCtx.createMediaStreamSource(stream);
      const analyser = audioCtx.createAnalyser();
      analyser.fftSize = 256;
      source.connect(analyser);
      analyserRef.current = analyser;

      const dataArray = new Uint8Array(analyser.frequencyBinCount);

      const tick = () => {
        if (cancelled) return;
        analyser.getByteFrequencyData(dataArray);
        let sum = 0;
        for (let i = 0; i < dataArray.length; i++) {
          sum += dataArray[i];
        }
        setLevel(sum / dataArray.length / 255);
        rafRef.current = requestAnimationFrame(tick);
      };

      rafRef.current = requestAnimationFrame(tick);

      return () => {
        cancelled = true;
        if (rafRef.current !== null) cancelAnimationFrame(rafRef.current);
        source.disconnect();
        analyser.disconnect();
        void audioCtx.close();
        analyserRef.current = null;
      };
    } catch {
      // Level preview is optional
      return;
    }
  }, [stream, enabled]);

  return level;
}

// =============================================================================
// COMPONENT
// =============================================================================

function MicSelector({
  onDeviceSelect,
  onStreamChange,
  showPreview = true,
  kind = "audioinput",
  size,
  className,
  ...props
}: MicSelectorProps) {
  const {
    devices,
    activeDeviceId,
    stream,
    hasPermission,
    error,
    requestPermission,
    selectDevice,
  } = useAudioDevices({ kind });

  const level = useLevelPreview(stream, showPreview && hasPermission);

  // Notify parent when stream changes
  React.useEffect(() => {
    onStreamChange?.(stream);
  }, [stream, onStreamChange]);

  const handleDeviceSelect = React.useCallback(
    async (device: AudioDevice) => {
      await selectDevice(device.deviceId);
      onDeviceSelect?.(device);
    },
    [selectDevice, onDeviceSelect]
  );

  const resolvedSize = size ?? "md";

  if (!hasPermission) {
    return (
      <div
        data-slot="mic-selector"
        className={cn(micSelectorVariants({ size: resolvedSize }), className)}
        {...props}
      >
        <div className="flex items-center justify-between">
          <span className="text-muted-foreground">Microphone Access</span>
          <button
            type="button"
            onClick={requestPermission}
            className="inline-flex items-center gap-1.5 rounded-md bg-primary px-3 py-1.5 text-xs font-medium text-primary-foreground hover:bg-primary/90 transition-colors"
          >
            <svg
              width="14"
              height="14"
              viewBox="0 0 14 14"
              fill="none"
              stroke="currentColor"
              strokeWidth="1.5"
            >
              <rect x="4.5" y="1" width="5" height="8" rx="2.5" />
              <path d="M3 6.5a4 4 0 0 0 8 0" />
              <line x1="7" y1="10.5" x2="7" y2="13" />
              <line x1="5" y1="13" x2="9" y2="13" />
            </svg>
            Allow Microphone
          </button>
        </div>
        {error && <span className="text-xs text-destructive">{error}</span>}
      </div>
    );
  }

  return (
    <div
      data-slot="mic-selector"
      className={cn(micSelectorVariants({ size: resolvedSize }), className)}
      {...props}
    >
      {/* Header */}
      <div className="flex items-center justify-between">
        <span className="text-xs font-medium text-muted-foreground uppercase tracking-wider">
          Microphone
        </span>
        {showPreview && (
          <div className="flex items-center gap-0.5 h-4">
            {[0, 1, 2, 3].map((i) => (
              <div
                key={i}
                className="w-0.5 rounded-full bg-primary transition-[height] duration-75"
                style={{
                  height: `${Math.max(20, level * 100 * (1 - i * 0.2))}%`,
                }}
              />
            ))}
          </div>
        )}
      </div>

      {/* Device list */}
      <div
        className="flex flex-col gap-1"
        role="radiogroup"
        aria-label="Select microphone"
      >
        {devices.length === 0 ? (
          <span className="text-xs text-muted-foreground py-1">
            No microphones found
          </span>
        ) : (
          devices.map((device) => {
            const isSelected = activeDeviceId === device.deviceId;
            return (
              <button
                key={device.deviceId}
                type="button"
                role="radio"
                aria-checked={isSelected}
                onClick={() => handleDeviceSelect(device)}
                className={cn(
                  "flex items-center gap-2 rounded-lg px-3 py-2 text-left text-sm transition-colors",
                  isSelected
                    ? "bg-primary/10 text-primary"
                    : "hover:bg-muted text-foreground"
                )}
              >
                <div
                  className={cn(
                    "w-3 h-3 rounded-full border-2 flex items-center justify-center shrink-0",
                    isSelected ? "border-primary" : "border-muted-foreground/40"
                  )}
                >
                  {isSelected && (
                    <div className="w-1.5 h-1.5 rounded-full bg-primary" />
                  )}
                </div>
                <span className="truncate">
                  {device.label || `Microphone ${device.deviceId.slice(0, 8)}`}
                </span>
              </button>
            );
          })
        )}
      </div>

      {/* Error */}
      {error && <span className="text-xs text-destructive">{error}</span>}
    </div>
  );
}

MicSelector.displayName = "MicSelector";

export { MicSelector, micSelectorVariants };
export type { MicSelectorProps };

"use client";

import { useCallback, useEffect, useState } from "react";

// =============================================================================
// TYPES
// =============================================================================

interface AudioDevice {
  /** Unique device identifier */
  deviceId: string;
  /** Human-readable device label (empty until permission granted) */
  label: string;
  /** Device kind: audioinput, audiooutput, videoinput */
  kind: MediaDeviceKind;
  /** Group ID (devices from same hardware share a groupId) */
  groupId: string;
}

interface UseAudioDevicesOptions {
  /** Filter to specific device kind. Default: "audioinput" */
  kind?: MediaDeviceKind;
  /** Whether to request permission on mount. Default: false */
  requestOnMount?: boolean;
}

interface UseAudioDevicesReturn {
  /** Available audio devices */
  devices: AudioDevice[];
  /** Currently active device ID */
  activeDeviceId: string | null;
  /** Active MediaStream from selected device */
  stream: MediaStream | null;
  /** Whether permission has been granted */
  hasPermission: boolean;
  /** Whether we're requesting permission */
  isRequesting: boolean;
  /** Error message */
  error: string | null;
  /** Request microphone permission and enumerate devices */
  requestPermission: () => Promise<void>;
  /** Select a specific device by ID */
  selectDevice: (deviceId: string) => Promise<void>;
  /** Stop the active stream */
  stopStream: () => void;
}

// =============================================================================
// HOOK
// =============================================================================

export function useAudioDevices(
  options: UseAudioDevicesOptions = {}
): UseAudioDevicesReturn {
  const { kind = "audioinput", requestOnMount = false } = options;

  const [devices, setDevices] = useState<AudioDevice[]>([]);
  const [activeDeviceId, setActiveDeviceId] = useState<string | null>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [hasPermission, setHasPermission] = useState(false);
  const [isRequesting, setIsRequesting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Enumerate devices (only returns labels after permission is granted)
  const enumerateDevices = useCallback(async () => {
    if (
      typeof navigator === "undefined" ||
      !navigator.mediaDevices?.enumerateDevices
    ) {
      setError("MediaDevices API not available");
      return;
    }

    try {
      const allDevices = await navigator.mediaDevices.enumerateDevices();
      const filtered = allDevices
        .filter((d) => d.kind === kind)
        .map((d) => ({
          deviceId: d.deviceId,
          label:
            d.label ||
            `${kind === "audioinput" ? "Microphone" : "Speaker"} ${d.deviceId.slice(0, 5)}`,
          kind: d.kind,
          groupId: d.groupId,
        }));
      setDevices(filtered);
    } catch {
      setError("Failed to enumerate devices");
    }
  }, [kind]);

  // Request permission
  const requestPermission = useCallback(async () => {
    if (
      typeof navigator === "undefined" ||
      !navigator.mediaDevices?.getUserMedia
    ) {
      setError("getUserMedia not available");
      return;
    }

    setIsRequesting(true);
    setError(null);

    try {
      const constraints: MediaStreamConstraints =
        kind === "audioinput" ? { audio: true } : { audio: true };

      const mediaStream =
        await navigator.mediaDevices.getUserMedia(constraints);
      setStream(mediaStream);
      setHasPermission(true);

      // Get the active device ID from the track
      const tracks = mediaStream.getAudioTracks();
      if (tracks.length > 0) {
        const settings = tracks[0].getSettings();
        setActiveDeviceId(settings.deviceId || null);
      }

      // Now enumerate with labels available
      await enumerateDevices();
    } catch (err) {
      if (err instanceof DOMException) {
        switch (err.name) {
          case "NotAllowedError":
            setError("Microphone permission denied");
            break;
          case "NotFoundError":
            setError("No microphone found");
            break;
          case "NotReadableError":
            setError("Microphone is in use by another application");
            break;
          default:
            setError(`Microphone error: ${err.message}`);
        }
      } else {
        setError("Failed to access microphone");
      }
    } finally {
      setIsRequesting(false);
    }
  }, [kind, enumerateDevices]);

  // Select a specific device
  const selectDevice = useCallback(
    async (deviceId: string) => {
      if (
        typeof navigator === "undefined" ||
        !navigator.mediaDevices?.getUserMedia
      ) {
        return;
      }

      // Stop existing stream
      if (stream) {
        stream.getTracks().forEach((t) => t.stop());
      }

      setError(null);
      setIsRequesting(true);

      try {
        const constraints: MediaStreamConstraints = {
          audio: { deviceId: { exact: deviceId } },
        };
        const mediaStream =
          await navigator.mediaDevices.getUserMedia(constraints);
        setStream(mediaStream);
        setActiveDeviceId(deviceId);
      } catch {
        setError("Failed to switch device");
      } finally {
        setIsRequesting(false);
      }
    },
    [stream]
  );

  // Stop stream
  const stopStream = useCallback(() => {
    if (stream) {
      stream.getTracks().forEach((t) => t.stop());
      setStream(null);
      setActiveDeviceId(null);
    }
  }, [stream]);

  // Request on mount if option is set
  useEffect(() => {
    if (requestOnMount) {
      requestPermission();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Listen for device changes (hot-plug)
  useEffect(() => {
    if (typeof navigator === "undefined" || !navigator.mediaDevices) return;

    const handler = () => {
      enumerateDevices();
    };

    navigator.mediaDevices.addEventListener("devicechange", handler);
    return () => {
      navigator.mediaDevices.removeEventListener("devicechange", handler);
    };
  }, [enumerateDevices]);

  // Cleanup stream on unmount
  useEffect(() => {
    return () => {
      if (stream) {
        stream.getTracks().forEach((t) => t.stop());
      }
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  return {
    devices,
    activeDeviceId,
    stream,
    hasPermission,
    isRequesting,
    error,
    requestPermission,
    selectDevice,
    stopStream,
  };
}

export type { AudioDevice, UseAudioDevicesOptions, UseAudioDevicesReturn };
